// ============================================================
// Normalize Job Completion Data
// Supports common CRM field naming conventions so the workflow
// works with ServiceTitan, Jobber, Housecall Pro, or any
// system that can POST JSON.
// ============================================================

const raw = $input.first().json;
const cfg = $('⚙️ Config').first().json;

const normalized = {
  customerId: raw.customerId || raw.customer_id || raw.id || '',
  customerName: raw.customerName || raw.customer_name || raw.name ||
    `${raw.firstName || raw.first_name || ''} ${raw.lastName || raw.last_name || ''}`.trim() || 'Valued Customer',
  customerPhone: raw.customerPhone || raw.customer_phone || raw.phone || raw.mobile || '',
  customerEmail: raw.customerEmail || raw.customer_email || raw.email || '',
  jobId: raw.jobId || raw.job_id || raw.orderId || raw.order_id || raw.invoiceId || raw.invoice_id || '',
  jobType: raw.jobType || raw.job_type || raw.service || raw.serviceType || raw.service_type || '',
  technicianName: raw.technicianName || raw.technician_name || raw.assignee || raw.tech || '',
  completedAt: raw.completedAt || raw.completed_at || raw.completedDate || new Date().toISOString()
};

normalized.hasPhone = !!normalized.customerPhone;
normalized.hasEmail = !!normalized.customerEmail;
normalized.channel = normalized.hasPhone ? 'sms' : 'email';

if (!normalized.hasPhone && !normalized.hasEmail) {
  throw new Error(
    `No contact method for customer "${normalized.customerName}" (job ${normalized.jobId}). ` +
    `Webhook must include a phone number or email address.`
  );
}

console.log(`Job ${normalized.jobId} complete for ${normalized.customerName} — will contact via ${normalized.channel}`);

return [{ json: normalized }];

// ============================================================
// Build Review Request Messages (SMS + Email)
// Constructs the micro-survey URL with a unique callback so
// the workflow resumes when the customer submits their rating.
// ============================================================

const customer = $('📝 Normalize Data').first().json;
const cfg = $('⚙️ Config').first().json;

// Build the callback URL that the micro-survey page will POST to
const callbackUrl = `${cfg.n8nWebhookBaseUrl}/webhook-waiting/${$execution.id}`;

// Build the survey URL the customer will click
const surveyUrl = `${cfg.microSurveyUrl}` +
  `?callback=${encodeURIComponent(callbackUrl)}` +
  `&business=${encodeURIComponent(cfg.businessName)}` +
  `&customer=${encodeURIComponent(customer.customerName)}`;

const firstName = customer.customerName.split(' ')[0];

// --- SMS Body ---
const smsBody = `Hi ${firstName}! Thanks for choosing ${cfg.businessName}` +
  `${customer.jobType ? ` for your ${customer.jobType}` : ''}. ` +
  `We'd love your feedback — it only takes 10 seconds:\n${surveyUrl}`;

// --- Email ---
const emailSubject = `How was your experience with ${cfg.businessName}?`;

const emailHtml = [
  `<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 520px; margin: 0 auto; padding: 24px;">`,
  `<p style="font-size: 16px; color: #1a1a1a;">Hi ${firstName},</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">Thank you for choosing <strong>${cfg.businessName}</strong>`,
  customer.jobType ? ` for your ${customer.jobType}` : '',
  `!</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">We'd love to hear about your experience. It only takes 10 seconds:</p>`,
  `<p style="margin: 28px 0; text-align: center;">`,
  `<a href="${surveyUrl}" style="background: #2563eb; color: #ffffff; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">Rate Your Experience</a>`,
  `</p>`,
  `<p style="font-size: 14px; color: #6b7280;">Your feedback helps us improve and helps other customers find us.</p>`,
  `<p style="font-size: 14px; color: #6b7280;">Thanks,<br><strong>${cfg.businessName}</strong></p>`,
  `</div>`
].join('\n');

// Pre-build SendGrid payload for the Email HTTP node
const sendgridPayload = {
  personalizations: [{ to: [{ email: customer.customerEmail }] }],
  from: { email: cfg.sendgridFromEmail, name: cfg.sendgridFromName || cfg.businessName },
  subject: emailSubject,
  content: [{ type: 'text/html', value: emailHtml }]
};

console.log(`Review request built for ${customer.customerName} — survey URL: ${surveyUrl}`);

return [{
  json: {
    ...customer,
    surveyUrl,
    callbackUrl,
    smsBody,
    emailSubject,
    emailHtml,
    sendgridPayload,
    firstName
  }
}];

// ============================================================
// Parse Rating from Micro-Survey Callback
// The Wait node outputs the webhook POST body from the
// micro-survey page. We extract the rating and merge it
// with the original customer data.
// ============================================================

const ratingData = $input.first().json;
const customer = $('📝 Normalize Data').first().json;
const cfg = $('⚙️ Config').first().json;

// Extract rating — support multiple field names
const rating = parseInt(
  ratingData.rating || ratingData.stars || ratingData.score || 0
);

const comment = ratingData.comment || ratingData.feedback || ratingData.message || '';

if (rating < 1 || rating > 5) {
  throw new Error(`Invalid rating received: ${rating}. Expected integer 1-5. Raw data: ${JSON.stringify(ratingData)}`);
}

const threshold = parseInt(cfg.ratingThreshold) || 4;
const isPositive = rating >= threshold;

console.log(`${customer.customerName} rated ${rating}/5 — ${isPositive ? 'POSITIVE → send review links' : 'NEGATIVE → save attempt'}`);

return [{
  json: {
    rating,
    comment,
    isPositive,
    ...customer,
    ratedAt: new Date().toISOString()
  }
}];

// ============================================================
// Build Positive Follow-Up
// Thank the customer and send them to Google/Yelp to leave
// a public review while their positive sentiment is fresh.
// ============================================================

const data = $input.first().json;
const cfg = $('⚙️ Config').first().json;

const firstName = data.customerName.split(' ')[0];

// --- SMS ---
const smsBody = `Thank you for the ${data.rating}-star rating, ${firstName}! ` +
  `Would you mind sharing your experience? It really helps us:\n\n` +
  `Google: ${cfg.googleReviewUrl}\n` +
  `Yelp: ${cfg.yelpReviewUrl}`;

// --- Email ---
const emailSubject = `Thank you for your ${data.rating}-star rating!`;
const emailHtml = [
  `<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 520px; margin: 0 auto; padding: 24px;">`,
  `<p style="font-size: 16px; color: #1a1a1a;">Hi ${firstName},</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">Thank you so much for the <strong>${data.rating}-star rating</strong>! We're thrilled you had a great experience.</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">Would you mind taking 30 seconds to share on one of these platforms? It makes a huge difference for us:</p>`,
  `<p style="margin: 28px 0; text-align: center;">`,
  `<a href="${cfg.googleReviewUrl}" style="background: #4285f4; color: #ffffff; padding: 14px 24px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 14px; margin-right: 12px;">Review on Google</a>`,
  `<a href="${cfg.yelpReviewUrl}" style="background: #d32323; color: #ffffff; padding: 14px 24px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 14px;">Review on Yelp</a>`,
  `</p>`,
  `<p style="font-size: 14px; color: #6b7280;">Thanks again for choosing <strong>${cfg.businessName}</strong>!</p>`,
  `</div>`
].join('\n');

const sendgridPayload = {
  personalizations: [{ to: [{ email: data.customerEmail }] }],
  from: { email: cfg.sendgridFromEmail, name: cfg.sendgridFromName || cfg.businessName },
  subject: emailSubject,
  content: [{ type: 'text/html', value: emailHtml }]
};

// --- Slack ---
const stars = Array(data.rating).fill('\u2b50').join('');
const slackMessage = `*${stars} ${data.rating}-Star Rating Received!*\n\n` +
  `*Customer:* ${data.customerName}\n` +
  `*Job:* ${data.jobType || 'N/A'} (${data.jobId})\n` +
  `*Rating:* ${stars}\n` +
  (data.comment ? `*Comment:* ${data.comment}\n` : '') +
  `\n_Sent Google & Yelp review links._`;

return [{
  json: {
    ...data,
    smsBody,
    emailSubject,
    emailHtml,
    sendgridPayload,
    slackMessage
  }
}];

// ============================================================
// Build Recovery Message for Low Ratings
// Empathetic response that opens the door for resolution.
// The goal: prevent a negative public review by showing
// the customer you care and will make it right.
// ============================================================

const data = $input.first().json;
const cfg = $('⚙️ Config').first().json;

const firstName = data.customerName.split(' ')[0];

// --- SMS ---
const smsBody = `Hi ${firstName}, thank you for your honest feedback. ` +
  `We're sorry your experience with ${cfg.businessName} wasn't what you expected. ` +
  `A member of our team will reach out to make things right.`;

// --- Email ---
const emailSubject = `We want to make things right, ${firstName}`;
const emailHtml = [
  `<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 520px; margin: 0 auto; padding: 24px;">`,
  `<p style="font-size: 16px; color: #1a1a1a;">Hi ${firstName},</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">Thank you for sharing your honest feedback about your experience with <strong>${cfg.businessName}</strong>.</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">We're sorry we didn't meet your expectations`,
  data.jobType ? ` with your ${data.jobType}` : '',
  `. Your satisfaction matters to us, and a member of our team will be reaching out personally to make things right.</p>`,
  `<p style="font-size: 16px; color: #1a1a1a;">If you'd like to reach us directly in the meantime, please reply to this email or call us.</p>`,
  `<p style="font-size: 14px; color: #6b7280;">Thank you for giving us the chance to improve,<br><strong>${cfg.businessName}</strong></p>`,
  `</div>`
].join('\n');

const sendgridPayload = {
  personalizations: [{ to: [{ email: data.customerEmail }] }],
  from: { email: cfg.sendgridFromEmail, name: cfg.sendgridFromName || cfg.businessName },
  subject: emailSubject,
  content: [{ type: 'text/html', value: emailHtml }]
};

// --- Slack (urgent) ---
const stars = Array(data.rating).fill('\u2b50').join('');
const slackMessage = `*\ud83d\udea8 Low Rating — Save Attempt Needed*\n\n` +
  `*Customer:* ${data.customerName}\n` +
  `*Phone:* ${data.customerPhone || 'N/A'}\n` +
  `*Email:* ${data.customerEmail || 'N/A'}\n` +
  `*Job:* ${data.jobType || 'N/A'} (${data.jobId})\n` +
  `*Rating:* ${stars} (${data.rating}/5)\n` +
  (data.comment ? `*Comment:* "${data.comment}"\n` : '') +
  `*Technician:* ${data.technicianName || 'N/A'}\n` +
  `\n_Recovery message sent. Follow up ASAP to prevent negative public review._`;

return [{
  json: {
    ...data,
    smsBody,
    emailSubject,
    emailHtml,
    sendgridPayload,
    slackMessage
  }
}];

